patch:
--- a/barrel_shifter.v
+++ b/barrel_shifter.v
@@ -1,7 +1,7 @@
 module barrel_shifter_64(
     input [63:0] data_in,
     input [5:0] shift_amount, direction,
     output reg [63:0] data_out
 );
-    always @(data_in or shift_amount)
+    always_comb
         case(direction)
             1'b0: data_out = data_in << shift_amount;
             1'b1: data_out = data_in >> shift_amount;

before_code:
module barrel_shifter_64(
    input [63:0] data_in,
    input [5:0] shift_amount, direction,
    output reg [63:0] data_out
);
    always @(data_in or shift_amount)
        case(direction)
            1'b0: data_out = data_in << shift_amount;
            1'b1: data_out = data_in >> shift_amount;
            default: data_out = 64'h0;
        endcase
endmodule

after_code:
module barrel_shifter_64(
    input [63:0] data_in,
    input [5:0] shift_amount, direction,
    output reg [63:0] data_out
);
    always_comb
        case(direction)
            1'b0: data_out = data_in << shift_amount;
            1'b1: data_out = data_in >> shift_amount;
            default: data_out = 64'h0;
        endcase
endmodule
